VALUES
('bookkeeper-moex-01612', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '小米公司自國外購入一台機器，定價為$300,000，由於小米公司在期限內付款，因此享有2%的現金折扣， 其他相關支出包含運費$12,000、關稅$15,000、安裝及試車費$32,000，此外，運送途中司機接到$5,000之 罰單，而公司為此機器購入未來1年期之保險$20,000。則此機器之成本為何？', '["$300,000", "$353,000", "$359,000", "$378,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01613', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司本年度稅前淨利$270,000，所得稅率25%，年初流通在外普通股為100,000股，7月1日收回普通 股20,000股，則當年度稅後每股盈餘為：', '["$3.00", "$2.025", "$2.5", "$2.25"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01614', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '達馬公司X1年1月1日有流通在外普通股1,200,000股，X1年5月1日達馬公司增資發行240,000股， 該公司在X1年9月1日再增資發行600,000股，則達馬公司X1年加權平均流通在外股數為：', '["1,200,000股", "1,560,000股", "1,620,000股", "2,040,000股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01615', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '東方公司 X1 年的期初在製品存貨為$5,000，本年投入直接原料$23,000，直接人工$15,000，間接製造成 本分攤率為直接人工成本的80%，期末在製品存貨為$8,000，則本期製成品成本為：', '["$63,000", "$53,750", "$47,000", "$35,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01616', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '大樑公司發行面額$100，5年期，利率3%之公司債，若發行當時市場利率為5%，則此公司債為：', '["溢價發行", "折價發行", "平價發行", "貼價發行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01617', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '大宇公司 X8 年度資料：發行公司債得款$500,000，現付公司債利息$50,000，現購存貨$95,000，現購庫 藏股$150,000，現購機器設備$350,000，發行特別股收現$400,000，支付特別股現金股利$100,000，則其 融資活動的淨現金流入為：', '["$900,000", "$800,000", "$650,000", "$600,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01618', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列關於我國綜合所得稅列舉扣除中房屋租金支出扣除之敘述，何者錯誤？', '["我國境外租金支出不得扣抵", "每一申報戶每年扣除額以12萬元為限", "每戶適用對象為納稅義務人及其配偶與受扶養親屬", "申報有購屋借款利息扣除者，其租金支出即不得扣除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01619', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司為其員工投保團體壽險（保費由營利事業負擔且以被保險員工之家屬為受益人），每人每月之保 險費為新臺幣1,800元，下列何項敘述正確？', '["該筆保險費免視為被保險員工之薪資所得", "該筆保險費須視為員工之薪資所得，惟員工可列舉保險費扣除", "該筆保險費為福利性所得，故須視為員工之薪資所得，但不可列舉扣除之", "該筆保險費應視為員工之所得，但應列於其他所得項下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01620', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國所得稅法規定，非居住者於同一課稅年度內，在我國境內居留合計不超過多少天者，其在我國境內 提供勞務，而自境外雇主取得之勞務報酬免稅？', '["30天", "60天", "90天", "183天"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01621', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '國外影片事業在中華民國境內無分支機構，經由其代理人出租影片之收入，應以其多少為在中華民國境 內之營利事業所得額？', '["全部", "二分之一", "三分之一", "四分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01622', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依我國所得稅法之規定，營利事業之會計年度起訖期間，原則上為每年之：', '["一月一日至十二月三十一日", "七月一日至次年六月三十日", "五月一日至次年四月三十日", "四月一日至次年三月三十一日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01623', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列信託行為中，何種情形須課徵所得稅？', '["因信託行為成立，委託人與受託人間信託財產之移轉", "信託關係存續中受託人變更時，原受託人與新受託人間信託財產之移轉", "因信託行為被解除，委託人由受託人取得之信託財產", "信託關係存續中，受託人管理信託財產所發生之收入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01624', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列敘述何者錯誤？', '["非適用勞動基準法之營利事業定有職工退休辦法者，每年度提列職工退休金準備不得超過當年度已付 薪資總額百分之四，並以費用列支", "營利事業全年所得額在新臺幣20萬元以下免徵營利事業所得稅", "營利事業之資本利息應列為盈餘分派", "營利事業所擁有之債權逾期二年經催收未有本金或利息之收取，且具催收證明者，得列為呆帳損失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01625', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '試問自民國102年度起，依101年8月8日修正通過之「所得基本稅額條例」第7條第1項規定計算之 基本所得額，在新臺幣多少元以下之營利事業可不適用本條例？', '["50萬元", "100萬元", "150萬元", "200萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
